Future<void> _handleContinueAsPassenger(BuildContext context) async {
  unawaited(_persistSessionRolePreference(UserRole.passenger));
  var switchSourceRole = _snapshotRoleSwitchSourceRole();
  final user = _authCredentialGateway.currentUser;
  if (user == null || user.isAnonymous) {
    context.push(_buildAuthRouteWithNextRole(_authNextRolePassenger));
    return;
  }

  try {
    final rolePreparation = await _ensureAuthProfileRoleUseCase.execute(
      EnsureAuthProfileRoleCommand(
        uid: user.uid,
        displayName: _resolveDisplayName(user),
        targetRole: UserRole.passenger,
      ),
    );
    switchSourceRole = rolePreparation.currentRole;
  } catch (_) {
    if (!context.mounted) {
      return;
    }
    _showInfo(
      context,
      _resolveProfileCheckFailureFeedbackMessageUseCase.execute(),
    );
    return;
  }

  if (!context.mounted) {
    return;
  }
  final destination = await _resolvePassengerHomeDestination(user);
  if (!context.mounted) {
    return;
  }
  _applyRoleSwitchNavigationPlan(
    context,
    fromRole: switchSourceRole,
    toRole: UserRole.passenger,
    targetLocation: destination,
  );
}

