  }
  if (!context.mounted) {
    return;
  }
  if (!status.isGranted) {
    context.push(
      _buildJoinErrorRoute(
        role: selectedRole,
        reason: _joinErrorCameraPermission,
      ),
    );
    return;
  }

  context.push(_buildJoinQrRoute(role: selectedRole));
}

Future<void> _handleJoinViaQr(
  BuildContext context, {
  required JoinRole selectedRole,
  required String rawPayload,
}) async {
  final srvCode = _extractSrvCodeFromQrPayload(rawPayload);
  if (srvCode == null) {
    if (context.mounted) {
      context.go(
        _buildJoinErrorRoute(
          role: selectedRole,
          reason: _joinErrorInvalidQr,
        ),
      );
    }
    return;
  }

  if (selectedRole == JoinRole.guest) {
    await _handleCreateGuestSession(
      context,
      JoinBySrvFormInput(
        srvCode: srvCode,
        name: _resolveGuestJoinDisplayName(),
        showPhoneToDriver: false,
        boardingArea: 'guest',
        notificationTime: '07:00',
      ),
      source: _JoinEntrySource.qr,
    );
    return;
  }

  await _handleJoinBySrvCode(
    context,
    JoinBySrvFormInput(
      srvCode: srvCode,
      name: _resolveQrJoinDisplayName(),
      showPhoneToDriver: false,
      boardingArea: 'QR',
      notificationTime: '07:00',
    ),
    source: _JoinEntrySource.qr,
  );
}

String _resolveQrJoinDisplayName() {
  final currentUser = _authCredentialGateway.currentUser;
  final candidate = currentUser?.displayName?.trim();
  if (candidate != null && candidate.length >= 2) {
    return candidate;
  }
  return 'Yolcu';
}

String _resolveGuestJoinDisplayName() {
  final currentUser = _authCredentialGateway.currentUser;
  final candidate = currentUser?.displayName?.trim();
  if (candidate != null && candidate.length >= 2) {
    return candidate;
  }
  return 'Misafir';
}

String? _extractSrvCodeFromQrPayload(String rawPayload) {
  final trimmed = rawPayload.trim();
  if (trimmed.isEmpty) {
    return null;
  }

  final upper = trimmed.toUpperCase();
  final strictCodeRegex = RegExp(r'^[ABCDEFGHJKLMNPQRSTUVWXYZ23456789]{6}$');
  if (strictCodeRegex.hasMatch(upper)) {
    return upper;
  }

  final srvPrefixedMatch =
      RegExp(r'SRV[-:\\s]?([ABCDEFGHJKLMNPQRSTUVWXYZ23456789]{6})')
          .firstMatch(upper);
  if (srvPrefixedMatch != null) {
    return srvPrefixedMatch.group(1);
  }

  final uri = Uri.tryParse(trimmed);
  if (uri != null) {
    final resolvedFromQuery = _resolveSrvCodeFromQueryUri(
      uri,
      strictCodeRegex: strictCodeRegex,
    );
    if (resolvedFromQuery != null) {
      return resolvedFromQuery;
    }
  }

  return null;
}
